import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET() {
  try {
    const orders = await prisma.order.findMany({
      orderBy: { createdAt: 'desc' },
    });
    return NextResponse.json(orders);
  } catch (error) {
    console.error('Error fetching orders:', error);
    return NextResponse.json({ error: 'Error al obtener pedidos' }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const data = await request.json();
    
    // Extraer campos que no pertenecen directamente al modelo Order o necesitan transformación
    // Aseguramos que dentistId esté presente
    if (!data.dentistId) {
        return NextResponse.json({ error: 'ID del dentista es requerido' }, { status: 400 });
    }

    const order = await prisma.order.create({
      data: {
        patientName: data.patientName,
        prosthesisType: data.prosthesisType,
        material: data.material,
        specifications: data.specifications || '',
        deliveryDate: new Date(data.deliveryDate),
        status: data.status || 'pendiente',
        notes: data.notes || '',
        priority: data.priority || 'normal',
        dentistName: data.dentistName || 'Desconocido', // Idealmente obtener del usuario
        dentist: {
            connect: { id: data.dentistId }
        }
      },
    });
    
    return NextResponse.json(order);
  } catch (error) {
    console.error('Error creating order:', error);
    return NextResponse.json({ error: 'Error al crear pedido' }, { status: 500 });
  }
}
